import { useState, useEffect } from "react";
import { useSelector } from "react-redux";
import { useParams, useNavigate } from "react-router-dom";
import { toast } from "react-toastify";

function EditCourse() {
  const { id } = useParams();
  const [name, setName] = useState("");
  const [file, setFile] = useState(null);
  const [existingFiles, setExistingFiles] = useState([]);
  const user = useSelector((state) => state.auth.user);
  const navigate = useNavigate();

  useEffect(() => {
    fetch(`http://localhost:3001/courses/${id}`)
      .then((res) => res.json())
      .then((data) => setName(data.name))
      .catch((error) => toast.error("Ошибка загрузки курса"));
    fetch(`http://localhost:3001/files?courseId=${id}`)
      .then((res) => res.json())
      .then((data) => setExistingFiles(data))
      .catch((error) => toast.error("Ошибка загрузки файлов"));
  }, [id]);

  async function handleSubmit(e) {
    e.preventDefault();
    let filePath = null;

    if (file) {
      const formData = new FormData();
      formData.append("file", file);
      try {
        const response = await fetch("http://localhost:3002/upload", {
          method: "POST",
          body: formData,
        });
        const data = await response.json();
        if (response.ok) {
          filePath = data.filePath;
        } else {
          toast.error("Не удалось загрузить файл");
          return;
        }
      } catch (error) {
        toast.error("Сетевая ошибка при загрузке файла");
        return;
      }
    }

    try {
      const response = await fetch(`http://localhost:3001/courses/${id}`, {
        method: "PATCH",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ name }),
      });

      if (response.ok) {
        if (filePath) {
          await fetch("http://localhost:3001/files", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
              courseId: parseInt(id),
              filePath,
              fileName: file.name,
            }),
          });
        }
        toast.success("Курс успешно обновлен!");
        navigate("/courses");
      } else {
        toast.error("Не удалось обновить курс");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при обновлении курса");
    }
  }

  if (user?.role !== "teacher") {
    return <div className="container mt-5"><h1>Доступ запрещен</h1></div>;
  }

  return (
    <div className="container mt-5">
      <div className="row justify-content-center">
        <div className="col-md-6">
          <div className="card">
            <div className="card-body">
              <h2 className="card-title text-center mb-4">Редактировать курс</h2>
              <form onSubmit={handleSubmit}>
                <div className="mb-3">
                  <label htmlFor="name" className="form-label">
                    Название курса
                  </label>
                  <input
                    type="text"
                    id="name"
                    className="form-control"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    required
                  />
                </div>
                <div className="mb-3">
                  <label htmlFor="file" className="form-label">
                    Добавить новый файл (опционально)
                  </label>
                  <input
                    type="file"
                    id="file"
                    className="form-control"
                    onChange={(e) => setFile(e.target.files[0])}
                  />
                </div>
                {existingFiles.length > 0 && (
                  <div className="mb-3">
                    <h5>Существующие файлы:</h5>
                    <ul className="list-group">
                      {existingFiles.map((f) => (
                        <li key={f.id} className="list-group-item">
                          <a href={`http://localhost:3002${f.filePath}`} download>
                            {f.fileName}
                          </a>
                        </li>
                      ))}
                    </ul>
                  </div>
                )}
                <button type="submit" className="btn btn-primary w-100">
                  Обновить
                </button>
              </form>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default EditCourse;
